-- Backfill the top-level market column from meta for the rows just inserted.
UPDATE public.travelers SET market = 'japan' WHERE meta->>'seed_batch' = 'jp-01';

-- ── Verify ──────────────────────────────────────────────────────────
SELECT COUNT(DISTINCT meta->>'person_id') AS people,
       COUNT(*)                            AS unit_rows
FROM   public.travelers WHERE meta->>'seed_batch' = 'jp-01';

SELECT meta->>'person_id' AS person, name, destination, duration, arrival_date,
       budget_per_day AS daily_yen, hotel_budget AS hotel_pax_yen,
       meta->>'origin_country' AS origin
FROM   public.travelers WHERE meta->>'seed_batch' = 'jp-01'
ORDER  BY (meta->>'person_id')::int, (meta->>'unit_order')::int;
